mapper.select:
SELECT COUNT(*)
FROM USERS u


		AND u.USER_ID LIKE CONCAT('%', #{q}, '%')


		AND u.USER_STATUS = #{status}


		AND u.REG_DATE >= #{regDateFrom}


		AND u.REG_DATE <= #{regDateTo}

SELECT u.USER_ID AS userId, u.NICKNAME AS nickname, u.USER_STATUS AS status, u.LAST_LOGIN_DATE AS lastLoginDate, u.REG_DATE AS regDate, CASE WHEN b.STATUS = 'ACTIVE' THEN 1 ELSE 0 END AS blacklisted FROM USERS u LEFT JOIN BLACKLIST b ON u.USER_ID = b.USER_ID AND b.STATUS = 'ACTIVE'
AND u.USER_ID LIKE CONCAT('%', #{q}, '%')
AND u.USER_STATUS = #{status}
AND u.REG_DATE >= #{regDateFrom}
AND u.REG_DATE <= #{regDateTo}
ORDER BY
u.REG_DATE ASC u.REG_DATE DESC u.LAST_LOGIN_DATE ASC u.LAST_LOGIN_DATE DESC u.USER_ID ASC u.USER_ID DESC u.USER_STATUS ASC u.USER_STATUS DESC u.REG_DATE DESC
u.REG_DATE DESC
LIMIT #{size} OFFSET #{offset}
